UPDATE price_list_entry
price_list_number = #{priceListNumber}, FMaterialId = #{FMaterialId}, FMaterialName = #{FMaterialName}, F_cty_BaseProperty = #{F_cty_BaseProperty}, F_GCHH = #{F_GCHH}, FPrice = #{FPrice}, F_GGSM = #{F_GGSM}, FNote = #{FNote}, FTaxPrice = #{FTaxPrice}, FUnitID = #{FUnitID}, FTaxRate = #{FTaxRate}, F100t5 = #{F100t5}, FPriceCoefficient = #{FPriceCoefficient}, FUpPrice = #{FUpPrice}, FDownPrice = #{FDownPrice}, FEntryEffectiveDate = #{FEntryEffectiveDate}, FEntryExpiryDate = #{FEntryExpiryDate}, F_WBZC = #{F_WBZC}, F_WBZK = #{F_WBZK}, F_WBZG = #{F_WBZG}, F_WBZTJ = #{F_WBZTJ}, F_WBZSL = #{F_WBZSL}, F_WBZDW = #{F_WBZDW}, F_MZ = #{F_MZ}, F_JZ = #{F_JZ}, F_bzsm = #{F_bzsm}, FRECENTDATE = #{FRECENTDATE}, F_cgshys = #{F_cgshys}, F_dzshqdl = #{F_dzshqdl}, F_ZXSMS = #{F_ZXSMS}, F_ZXSMSTP = #{F_ZXSMSTP}, F_BCGG = #{F_BCGG}, F_kppm = #{F_kppm}, Fxjr = #{Fxjr}, Fsfyyywxj = #{Fsfyyywxj}, Fcpzlyq = #{Fcpzlyq}, F_QDL = #{F_QDL}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT
pe.price_list_number,
bm.number as FMaterialId,
pe.FMaterialName,
pe.F_cty_BaseProperty,
pe.F_GCHH,
pe.FPrice,
pe.F_GGSM,
pe.FNote,
pe.FTaxPrice,
bd.name as FUnitID,
pe.FTaxRate,
pe.F100t5,
pe.FPriceCoefficient,
pe.FUpPrice,
pe.FDownPrice,
pe.FEntryEffectiveDate,
pe.FEntryExpiryDate,
pe.F_WBZC,
pe.F_WBZK,
pe.F_WBZG,
pe.F_WBZTJ,
pe.F_WBZSL,
bdy.name as F_WBZDW,
pe.F_MZ,
pe.F_JZ,
pe.F_bzsm,
pe.FRECENTDATE,
pe.F_cgshys,
pe.F_dzshqdl,
pe.F_ZXSMS,
pe.F_ZXSMSTP,
pe.F_BCGG,
pe.F_kppm,
pe.Fxjr,
pe.Fsfyyywxj,
pe.Fcpzlyq,
pe.F_QDL,
pe.created_at AS createdAt,
pe.updated_at AS updatedAt
FROM
price_list_entry  pe
LEFT JOIN bymaterial_dictionary bd on pe.FUnitID=bd.kingdee and bd.category='unit'
LEFT JOIN bymaterial_dictionary bdy on pe.F_WBZDW=bd.kingdee and bdy.category='unit'
LEFT JOIN by_material bm on pe.FMaterialId=bm.k3_id

    AND price_list_number = #{priceListNumber}
    AND FMaterialId = #{FMaterialId}
    AND FMaterialName = #{FMaterialName}
    AND F_cty_BaseProperty = #{F_cty_BaseProperty}
    AND F_GCHH = #{F_GCHH}
    AND FPrice = #{FPrice}
    AND F_GGSM = #{F_GGSM}
    AND FNote = #{FNote}
    AND FTaxPrice = #{FTaxPrice}
    AND FUnitID = #{FUnitID}
    AND FTaxRate = #{FTaxRate}
    AND F100t5 = #{F100t5}
    AND FPriceCoefficient = #{FPriceCoefficient}
    AND FUpPrice = #{FUpPrice}
    AND FPriceCoefficient = #{FPriceCoefficient}
    AND FDownPrice = #{FDownPrice}
    AND FEntryEffectiveDate >= #{FEntryEffectiveDate}
    AND FEntryExpiryDate <= #{FEntryExpiryDate}
    AND F_WBZDW = #{F_WBZDW}
    AND F_bzsm LIKE CONCAT('%', #{F_bzsm}, '%')
    AND F_cgshys = #{F_cgshys}
    AND F_ZXSMS LIKE CONCAT('%', #{F_ZXSMS}, '%')
    AND F_kppm LIKE CONCAT('%', #{F_kppm}, '%')
    AND Fxjr = #{Fxjr}
    AND Fsfyyywxj = #{Fsfyyywxj}
    AND Fcpzlyq LIKE CONCAT('%', #{Fcpzlyq}, '%')

ORDER BY created_at DESC
